sysevent_script_action.script:
var logger = new Logger('PickUpCertificateHandler');
logger.debug('Starting script action');

function updateCloseNotes(current, message) {
    var timestamp = new GlideDateTime().getValue();
    var closeNotes = timestamp + ' - ' + message;
    var prevCloseNotes = current.getValue('close_notes');
    current.close_notes = closeNotes + '\n' + prevCloseNotes;
    current.update();
}

try {
    logger.debug('Handling the event {0}, related to certificate request record. Payload: {1}.', event.name, event.parm1);

    var httpRequestUtils = new HttpRequestUtils();
    var certificateService = new CertificateService();
    var payload = JSON.parse(event.parm1);

    var currentTime = new GlideDateTime();
    var isExpired = currentTime.after(new GlideDateTime(payload.expirationDate));

    if (isExpired) {
        throw new Error(
            'Your job is expired. Note that job is expired after 10 days of tries. You should manually check the status of your certificate.'
        );
    }

    // 86400 sec = 1 day
    // limits timeout time
    if (payload.timeout < 86400) {
        payload.timeout *= 2;
    }

    var certificate = httpRequestUtils.post(
        Constants.URL.pickUpCertificateUrl.replace('{request_id}', payload.requestId),
        payload.body
    );
    certificate = JSON.parse(certificate);
    if (certificate.status.toLowerCase() === 'ISSUED'.toLowerCase()) {
        logger.info('Certificate for request id {0} has been successfully picked up', payload.requestId);

        certificateService.saveCertificate({
                serialNumber: certificate.serial_number,
                deliveryFormat: certificate.delivery_format,
                certificate: certificate.certificate,
            },
            payload.certificateRequestSysId
        );

        updateCloseNotes(current, 'Your certificate has been issued!');
        EmailHelpers.sendCertificateGeneratedNotification({
            current: current
        });
    } else {
        logger.debug(
            'Certificate for request id {0} has not been picked up. Certificate status - {1}. Submit event to run an action again.',
            payload.requestId,
            certificate.status
        );
        var processTime = new GlideDateTime();
        processTime.addSeconds(payload.timeout);
        gs.eventQueueScheduled(Constants.EVENT.pickUpCertificate, current, JSON.stringify(payload), '', processTime);
    }
} catch (error) {
    var message = 'Error ocurred on certificate pick up - ' + error;
    logger.error(message);

    updateCloseNotes(current, message);
    EmailHelpers.sendCertificateFailedNotification({
        current: current
    });
}

logger.debug('Finished script action');
